// --- data-access.js ---
function requireData(key) {
    const data = window.SESTOSENS_DATA?.[key];
    if (!data) {
        throw new Error(`Dati mancanti: ${key}. Controlla che data/${key}.js sia caricato prima del bundle.`);
    }
    return data;
}

