// --- utils.js ---
function cleanWord(word) {
    return word.toLowerCase().normalize('NFD').replace(/\p{M}/gu, '').replace(/[^a-z]/g, '');
}

function createSoftStarTexture(THREE) {
    const size = 64;
    const canvas = document.createElement('canvas');
    canvas.width = size;
    canvas.height = size;
    const context = canvas.getContext('2d');
    const gradient = context.createRadialGradient(size / 2, size / 2, 0, size / 2, size / 2, size / 2);
    gradient.addColorStop(0, 'rgba(255,255,255,1)');
    gradient.addColorStop(0.2, 'rgba(255,255,255,0.92)');
    gradient.addColorStop(0.45, 'rgba(255,255,255,0.4)');
    gradient.addColorStop(1, 'rgba(255,255,255,0)');
    context.fillStyle = gradient;
    context.fillRect(0, 0, size, size);
    return new THREE.CanvasTexture(canvas);
}

function hashString(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = ((hash << 5) - hash) + str.charCodeAt(i);
        hash |= 0;
    }
    return Math.abs(hash);
}

// --- emotions.js ---
let emotionsData = null;
let ghostNameIndex = 0;
let shuffledEmotions = [];

async function loadEmotions() {
    emotionsData = getEmotions();
    emotionsData.sentimentPools.neutral = emotionsData.lexicon;
    resetEmotionNames();
    return emotionsData;
}

function resetEmotionNames() {
    ghostNameIndex = 0;
    shuffledEmotions = [...emotionsData.lexicon].sort(() => Math.random() - 0.5);
}

function getNextEmotionName() {
    const name = shuffledEmotions[ghostNameIndex % shuffledEmotions.length];
    ghostNameIndex += 1;
    return name;
}

function scoreHintMatch(word, hint) {
    if (hint.length < 2 || word.length < 2) return 0;
    if (word === hint) return 10;

    const minStem = 4;
    const stemLen = Math.min(6, word.length, hint.length);
    if (stemLen >= minStem && word.slice(0, stemLen) === hint.slice(0, stemLen)) return 7;

    if (hint.length >= 5 && word.includes(hint)) return 5;
    if (word.length >= 5 && hint.includes(word)) return 4;

    return 0;
}

function detectPhraseSentiment(normalized) {
    const scores = { positive: 0, negative: 0, anxious: 0, tender: 0, longing: 0 };
    const phrase = normalized.join(' ');
    for (const [tone, stems] of Object.entries(emotionsData.phraseSentiment)) {
        for (const stem of stems) {
            if (phrase.includes(stem)) scores[tone] += stem.length >= 5 ? 2 : 1;
        }
    }
    const ranked = Object.entries(scores).sort((a, b) => b[1] - a[1]);
    if (ranked[0][1] === 0) return 'neutral';
    if (ranked[0][1] === ranked[1][1]) return 'neutral';
    return ranked[0][0];
}

function scoreEmotionsFromWords(normalized) {
    const results = [];
    const stopWords = new Set(emotionsData.stopWords);

    for (const emotion of emotionsData.lexicon) {
        const hints = emotionsData.emotionHints[emotion] || [cleanWord(emotion)];
        let total = 0;
        let exactMatches = 0;
        let bestMatch = 0;
        let longestHint = 0;
        let matchedWords = 0;

        for (const word of normalized) {
            if (stopWords.has(word)) continue;

            let wordBest = 0;
            for (const hint of hints) {
                const score = scoreHintMatch(word, hint);
                if (score > 0) {
                    wordBest = Math.max(wordBest, score);
                    longestHint = Math.max(longestHint, hint.length);
                }
            }

            const emotionStem = cleanWord(emotion);
            const directScore = scoreHintMatch(word, emotionStem);
            if (directScore > 0) {
                wordBest = Math.max(wordBest, directScore + 2);
            }

            if (wordBest > 0) {
                total += wordBest;
                matchedWords += 1;
                if (wordBest >= 10) exactMatches += 1;
                bestMatch = Math.max(bestMatch, wordBest);
            }
        }

        if (matchedWords > 1) {
            total += matchedWords * 4;
        }

        if (total > 0) {
            results.push({ emotion, total, exactMatches, bestMatch, longestHint, matchedWords });
        }
    }
    return results;
}

function pickBestEmotionScore(results) {
    results.sort((a, b) => (
        b.total - a.total
        || b.matchedWords - a.matchedWords
        || b.exactMatches - a.exactMatches
        || b.bestMatch - a.bestMatch
        || b.longestHint - a.longestHint
    ));
    return results[0]?.emotion;
}

function sentimentFallbackEmotion(normalized, sentiment) {
    const pool = emotionsData.sentimentPools[sentiment] || emotionsData.sentimentPools.neutral;
    let best = null;
    let bestScore = 0;
    for (const emotion of pool) {
        const stem = cleanWord(emotion);
        let score = 0;
        for (const word of normalized) {
            score += scoreHintMatch(word, stem);
            for (let i = 3; i <= Math.min(word.length, stem.length); i += 1) {
                if (word.slice(0, i) === stem.slice(0, i)) score += i;
            }
        }
        if (score > bestScore) {
            bestScore = score;
            best = emotion;
        }
    }
    if (best) return best;
    let sum = 0;
    normalized.forEach((word) => {
        for (const char of word) sum += char.charCodeAt(0);
    });
    return pool[sum % pool.length];
}

function deriveEmotionName(words) {
    const normalized = words.map(cleanWord).filter(Boolean);
    if (!normalized.length) return emotionsData.lexicon[0];

    for (const word of normalized) {
        const direct = emotionsData.lexicon.find((emotion) => cleanWord(emotion) === word);
        if (direct) return direct;
    }

    const sentiment = detectPhraseSentiment(normalized);
    const scored = scoreEmotionsFromWords(normalized);

    if (scored.length) {
        const sentimentBoost = emotionsData.sentimentBoost;
        const positiveEmotions = new Set(sentimentBoost.positive.concat(['incanto', 'meraviglia', 'euforia']));
        const boostSet = new Set(sentimentBoost[sentiment] || []);
        for (const entry of scored) {
            if (boostSet.has(entry.emotion)) entry.total += 4;
            if (sentiment === 'negative' && positiveEmotions.has(entry.emotion)) entry.total -= 6;
        }
        const best = pickBestEmotionScore(scored);
        if (best) return best;
    }

    return sentimentFallbackEmotion(normalized, sentiment);
}

// --- audio.js ---
class AudioManager {
    constructor(config) {
        this.config = config.audio;
        this.INTRO_VOLUME = this.config.introVolume;
        this.INTRO_AMBIENT_VOLUME = this.config.introAmbientVolume;
        this.TOUCH_VOLUME = this.config.touchVolume;

        this.introSound = document.getElementById('intro-audio');
        this.touchSoundTemplate = document.getElementById('touch-audio');
        this.introSound.volume = this.INTRO_VOLUME;
        this.introSound.load();
        this.touchSoundTemplate.volume = this.TOUCH_VOLUME;

        this.touchSoundPool = [this.touchSoundTemplate, ...Array.from({ length: this.config.touchPoolSize }, () => {
            const audio = new Audio('./star2.mp3');
            audio.preload = 'auto';
            audio.volume = this.TOUCH_VOLUME;
            return audio;
        })];

        this.touchSoundIndex = 0;
        this.touchAudioContext = null;
        this.touchSampleBuffer = null;
        this.touchSampleLoadPromise = null;
        this.audioUnlocked = false;
        this.introFadeActive = false;
        this.introAmbientMode = false;
        this.introShouldPlay = true;
        this.introFadeRaf = null;
    }

    startIntroSound() {
        if (!this.introShouldPlay || this.introFadeActive || !this.audioUnlocked) return;

        this.introSound.volume = this.introAmbientMode ? this.INTRO_AMBIENT_VOLUME : this.INTRO_VOLUME;
        if (!this.introAmbientMode) {
            this.introSound.currentTime = 0;
        }

        const playAttempt = this.introSound.play();
        if (playAttempt) {
            playAttempt.catch(() => {
                this.introSound.load();
                this.introSound.play().catch(() => {});
            });
        }
    }

    primeTouchAudioContext() {
        if (!this.touchAudioContext) {
            this.touchAudioContext = new (window.AudioContext || window.webkitAudioContext)();
        }
        if (this.touchAudioContext.state === 'suspended') {
            this.touchAudioContext.resume();
        }
    }

    async fetchTouchSampleArrayBuffer() {
        if (window.location.protocol === 'file:') {
            throw new Error('Su file:// l\'audio usa il fallback HTMLAudioElement.');
        }

        const paths = [...this.config.paths.touch, this.touchSoundTemplate.currentSrc].filter(Boolean);
        for (const path of paths) {
            try {
                const response = await fetch(path);
                if (response.ok) {
                    return await response.arrayBuffer();
                }
            } catch (_) {}
        }
        throw new Error('Impossibile caricare star2.mp3');
    }

    loadTouchSampleBuffer() {
        if (this.touchSampleBuffer) {
            return Promise.resolve(this.touchSampleBuffer);
        }
        if (this.touchSampleLoadPromise) {
            return this.touchSampleLoadPromise;
        }

        this.touchSampleLoadPromise = (async () => {
            this.primeTouchAudioContext();
            const arrayBuffer = await this.fetchTouchSampleArrayBuffer();
            this.touchSampleBuffer = await this.touchAudioContext.decodeAudioData(arrayBuffer.slice(0));
            return this.touchSampleBuffer;
        })().catch((error) => {
            this.touchSampleLoadPromise = null;
            throw error;
        });

        return this.touchSampleLoadPromise;
    }

    unlockAudio() {
        if (!this.audioUnlocked) {
            this.audioUnlocked = true;
            this.startIntroSound();
            this.primeTouchAudioContext();
            if (this.touchAudioContext) {
                this.touchAudioContext.resume()
                    .then(() => this.loadTouchSampleBuffer())
                    .catch(() => this.loadTouchSampleBuffer().catch(() => {}));
            } else {
                this.loadTouchSampleBuffer().catch(() => {});
            }

            for (const sound of this.touchSoundPool) {
                const attempt = sound.play();
                if (attempt) {
                    attempt.then(() => {
                        sound.pause();
                        sound.currentTime = 0;
                    }).catch(() => {});
                }
            }
            return;
        }

        this.startIntroSound();
    }

    makeDistortionCurve(amount) {
        const samples = 44100;
        const curve = new Float32Array(samples);
        const deg = Math.PI / 180;
        for (let i = 0; i < samples; i++) {
            const x = (i * 2) / samples - 1;
            curve[i] = ((3 + amount) * x * 20 * deg) / (Math.PI + amount * Math.abs(x));
        }
        return curve;
    }

    getWordSoundProfile(starNode) {
        const word = starNode?.word || '';
        const hash = hashString(word + starNode?.starIndex);
        const order = starNode?.wordOrderIndex ?? 0;
        return {
            playbackRate: 0.86 + (hash % 28) / 100 + order * 0.028,
            filterFreq: 520 + (hash % 1400),
            filterQ: 0.45 + (hash % 12) / 10,
            startOffset: (hash % 45) / 1000,
            duration: 0.16 + (hash % 20) / 100,
            microGlitch: hash % 7 === 0
        };
    }

    playTouchSample({
        playbackRate = 1,
        startOffset = 0,
        duration = 0.22,
        volume = this.TOUCH_VOLUME,
        filterType = 'bandpass',
        filterFreq = 900,
        filterQ = 0.7,
        distortion = 0,
        delay = 0
    }) {
        if (!this.touchAudioContext || !this.touchSampleBuffer) return;

        const ctx = this.touchAudioContext;
        const now = ctx.currentTime + delay;
        const playDuration = Math.min(duration, this.touchSampleBuffer.duration - startOffset);
        if (playDuration <= 0) return;

        const source = ctx.createBufferSource();
        source.buffer = this.touchSampleBuffer;
        source.playbackRate.value = playbackRate;

        const filter = ctx.createBiquadFilter();
        filter.type = filterType;
        filter.frequency.value = filterFreq;
        filter.Q.value = filterQ;

        const gain = ctx.createGain();
        gain.gain.setValueAtTime(volume, now);
        gain.gain.linearRampToValueAtTime(0, now + playDuration + 0.05);

        let output = source;
        if (distortion > 0) {
            const shaper = ctx.createWaveShaper();
            shaper.curve = this.makeDistortionCurve(distortion);
            source.connect(shaper);
            output = shaper;
        }

        output.connect(filter);
        filter.connect(gain);
        gain.connect(ctx.destination);
        source.start(now, startOffset, playDuration);
    }

    playErrorTouchSound() {
        if (!this.touchAudioContext || !this.touchSampleBuffer) return;

        const ctx = this.touchAudioContext;
        const now = ctx.currentTime;
        const sliceCount = 3 + Math.floor(Math.random() * 3);

        for (let i = 0; i < sliceCount; i++) {
            this.playTouchSample({
                playbackRate: 0.42 + Math.random() * 0.22,
                startOffset: Math.random() * Math.max(0.01, this.touchSampleBuffer.duration - 0.08),
                duration: 0.05 + Math.random() * 0.07,
                volume: this.TOUCH_VOLUME * (0.75 + Math.random() * 0.35),
                filterType: 'lowpass',
                filterFreq: 420 + Math.random() * 500,
                filterQ: 1.4,
                distortion: 55 + Math.random() * 40,
                delay: i * (0.018 + Math.random() * 0.022)
            });
        }

        const osc = ctx.createOscillator();
        const oscFilter = ctx.createBiquadFilter();
        const oscGain = ctx.createGain();
        osc.type = 'square';
        osc.frequency.setValueAtTime(210 + Math.random() * 90, now);
        osc.frequency.exponentialRampToValueAtTime(55, now + 0.16);
        oscFilter.type = 'lowpass';
        oscFilter.frequency.value = 680;
        oscGain.gain.setValueAtTime(0.035, now);
        oscGain.gain.exponentialRampToValueAtTime(0.001, now + 0.16);
        osc.connect(oscFilter);
        oscFilter.connect(oscGain);
        oscGain.connect(ctx.destination);
        osc.start(now);
        osc.stop(now + 0.18);
    }

    playWordTouchSound(starNode, type) {
        if (!this.touchAudioContext || !this.touchSampleBuffer) return;

        const profile = this.getWordSoundProfile(starNode);

        if (type === 'connect') {
            this.playTouchSample({
                playbackRate: profile.playbackRate * 1.08,
                startOffset: profile.startOffset,
                duration: profile.duration + 0.08,
                volume: this.TOUCH_VOLUME * 1.1,
                filterType: 'lowpass',
                filterFreq: 4800,
                filterQ: 0.45
            });
            this.playTouchSample({
                playbackRate: profile.playbackRate * 1.24,
                startOffset: profile.startOffset * 0.5,
                duration: profile.duration * 0.6,
                volume: this.TOUCH_VOLUME * 0.6,
                filterType: 'lowpass',
                filterFreq: 3600,
                filterQ: 0.5,
                delay: 0.045
            });
            return;
        }

        this.playTouchSample({
            playbackRate: profile.playbackRate,
            startOffset: profile.startOffset,
            duration: profile.duration,
            volume: this.TOUCH_VOLUME,
            filterType: 'lowpass',
            filterFreq: Math.min(profile.filterFreq + 1200, 5200),
            filterQ: 0.55
        });

        if (profile.microGlitch) {
            this.playTouchSample({
                playbackRate: profile.playbackRate * 0.72,
                startOffset: profile.startOffset + 0.03,
                duration: 0.04,
                volume: this.TOUCH_VOLUME * 0.45,
                filterType: 'lowpass',
                filterFreq: 900,
                filterQ: 2,
                distortion: 18,
                delay: 0.03
            });
        }
    }

    getTouchSoundType(starNode, previousSelected) {
        if (!starNode.isWord) return 'error';
        if (previousSelected && previousSelected !== starNode) {
            if (!previousSelected.isWord) return 'error';
            return 'connect';
        }
        return 'word';
    }

    playTouchFallback(type, starNode) {
        const profile = starNode?.isWord ? this.getWordSoundProfile(starNode) : null;

        const playOne = (rate, volume, offset = 0, delay = 0) => {
            const sound = this.touchSoundPool[this.touchSoundIndex];
            this.touchSoundIndex = (this.touchSoundIndex + 1) % this.touchSoundPool.length;
            const start = () => {
                sound.currentTime = offset;
                sound.volume = volume;
                sound.playbackRate = rate;
                sound.play().catch(() => {});
            };
            if (delay > 0) {
                setTimeout(start, delay);
            } else {
                start();
            }
        };

        if (type === 'error') {
            playOne(0.52 + Math.random() * 0.1, this.TOUCH_VOLUME * 0.9, Math.random() * 0.04);
            playOne(0.38 + Math.random() * 0.08, this.TOUCH_VOLUME * 0.7, Math.random() * 0.06, 28);
            playOne(0.62 + Math.random() * 0.1, this.TOUCH_VOLUME * 0.55, Math.random() * 0.05, 58);
            return;
        }

        if (type === 'connect') {
            const rate = (profile?.playbackRate ?? 1) * 1.1;
            playOne(rate, this.TOUCH_VOLUME);
            playOne(rate * 1.18, this.TOUCH_VOLUME * 0.55, profile?.startOffset ?? 0, 42);
            return;
        }

        playOne(profile?.playbackRate ?? 0.95 + Math.random() * 0.15, this.TOUCH_VOLUME, profile?.startOffset ?? 0);
    }

    playProcessedTouchSound(type, starNode) {
        if (!this.touchSampleBuffer || !this.touchAudioContext) return false;
        if (this.touchAudioContext.state !== 'running') return false;

        if (type === 'error') {
            this.playErrorTouchSound();
        } else {
            this.playWordTouchSound(starNode, type);
        }
        return true;
    }

    playStarTouchSound(type, starNode) {
        if (!this.audioUnlocked) return;

        this.primeTouchAudioContext();

        if (!this.playProcessedTouchSound(type, starNode)) {
            this.playTouchFallback(type, starNode);
        }

        if (!this.touchSampleBuffer || this.touchAudioContext?.state !== 'running') {
            this.loadTouchSampleBuffer()
                .then(() => {
                    if (this.touchAudioContext?.state === 'suspended') {
                        return this.touchAudioContext.resume();
                    }
                })
                .catch(() => {});
        }
    }

    fadeIntroToAmbient(durationMs = this.config.introFadeMs) {
        if (this.introAmbientMode || this.introFadeActive) return;
        if (!this.introShouldPlay || this.introSound.paused) return;

        this.introFadeActive = true;

        const startVolume = this.introSound.volume || this.INTRO_VOLUME;
        const startTime = performance.now();

        const fadeStep = (now) => {
            const progress = Math.min((now - startTime) / durationMs, 1);
            this.introSound.volume = startVolume + (this.INTRO_AMBIENT_VOLUME - startVolume) * progress;

            if (progress < 1) {
                this.introFadeRaf = requestAnimationFrame(fadeStep);
                return;
            }

            this.introAmbientMode = true;
            this.introFadeActive = false;
            this.introFadeRaf = null;
        };

        this.introFadeRaf = requestAnimationFrame(fadeStep);
    }

    stopIntroSound(durationMs = this.config.stopIntroMs) {
        if (!this.introShouldPlay && this.introSound.paused) return;

        this.introShouldPlay = false;
        this.introAmbientMode = false;
        this.introFadeActive = false;

        if (this.introFadeRaf !== null) {
            cancelAnimationFrame(this.introFadeRaf);
            this.introFadeRaf = null;
        }

        if (this.introSound.paused) {
            this.introSound.currentTime = 0;
            this.introSound.volume = this.INTRO_VOLUME;
            return;
        }

        const startVolume = this.introSound.volume;
        const startTime = performance.now();

        const fadeStep = (now) => {
            const progress = Math.min((now - startTime) / durationMs, 1);
            this.introSound.volume = startVolume * (1 - progress);

            if (progress < 1) {
                this.introFadeRaf = requestAnimationFrame(fadeStep);
                return;
            }

            this.introSound.pause();
            this.introSound.currentTime = 0;
            this.introSound.volume = this.INTRO_VOLUME;
            this.introFadeRaf = null;
        };

        this.introFadeRaf = requestAnimationFrame(fadeStep);
    }
}

// --- starfield.js ---
function createStarfield(config, onOrbitChange) {
    const { camera: camCfg, stars: starCfg, controls: ctrlCfg } = config;

    const starTexture = createSoftStarTexture(THREE);

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(starCfg.backgroundColor);

    const camera = new THREE.PerspectiveCamera(
        camCfg.fov,
        window.innerWidth / window.innerHeight,
        camCfg.near,
        camCfg.far
    );
    camera.position.set(0, 0, camCfg.introDistanceStart);

    const renderer = new THREE.WebGLRenderer({
        antialias: true,
        preserveDrawingBuffer: true
    });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.domElement.style.position = 'fixed';
    renderer.domElement.style.inset = '0';
    renderer.domElement.style.zIndex = '0';
    renderer.domElement.style.touchAction = 'none';
    document.body.prepend(renderer.domElement);

    const labelRenderer = new CSS2DRenderer();
    labelRenderer.setSize(window.innerWidth, window.innerHeight);
    labelRenderer.domElement.style.position = 'fixed';
    labelRenderer.domElement.style.inset = '0';
    labelRenderer.domElement.style.pointerEvents = 'none';
    labelRenderer.domElement.style.zIndex = '5';
    document.body.appendChild(labelRenderer.domElement);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = ctrlCfg.dampingFactor;
    controls.autoRotate = true;
    controls.autoRotateSpeed = ctrlCfg.autoRotateSpeed;
    controls.enableZoom = true;
    controls.enablePan = true;
    controls.zoomSpeed = ctrlCfg.zoomSpeed;
    controls.panSpeed = ctrlCfg.panSpeed;
    controls.minDistance = ctrlCfg.minDistance;
    controls.maxDistance = ctrlCfg.maxDistance;
    controls.addEventListener('start', () => onOrbitChange(true));
    controls.addEventListener('end', () => onOrbitChange(false));

    const starCount = starCfg.count;
    const geometry = new THREE.BufferGeometry();
    const position = new Float32Array(starCount * 3);
    const sizes = new Float32Array(starCount);

    for (let i = 0; i < starCount * 3; i += 3) {
        position[i] = (Math.random() - 0.5) * starCfg.fieldSpread;
        position[i + 1] = (Math.random() - 0.5) * starCfg.fieldSpread;
        position[i + 2] = (Math.random() - 0.5) * starCfg.fieldSpread;
        sizes[i / 3] = Math.random() * 3 + 10;
    }

    geometry.setAttribute('position', new THREE.BufferAttribute(position, 3));
    geometry.setAttribute('size', new THREE.BufferAttribute(sizes, 1));

    const material = new THREE.PointsMaterial({
        color: 0xffffff,
        size: starCfg.defaultSize,
        map: starTexture,
        alphaMap: starTexture,
        sizeAttenuation: true,
        transparent: true,
        opacity: starCfg.defaultOpacity,
        alphaTest: 0.01,
        depthWrite: false
    });

    const stars = new THREE.Points(geometry, material);
    scene.add(stars);

    const wordStarsGroup = new THREE.Group();
    const linesGroup = new THREE.Group();
    const ghostConstellationsGroup = new THREE.Group();
    scene.add(wordStarsGroup);
    scene.add(linesGroup);
    scene.add(ghostConstellationsGroup);

    const wordGlimmerGeometry = new THREE.BufferGeometry();
    const wordGlimmerMaterial = new THREE.PointsMaterial({
        color: 0xffffff,
        size: 2.4,
        map: starTexture,
        alphaMap: starTexture,
        transparent: true,
        opacity: 0.3,
        sizeAttenuation: true,
        alphaTest: 0.01,
        depthWrite: false
    });
    const wordGlimmerPoints = new THREE.Points(wordGlimmerGeometry, wordGlimmerMaterial);
    wordStarsGroup.add(wordGlimmerPoints);

    const hoverGlow = new THREE.Sprite(new THREE.SpriteMaterial({
        map: starTexture,
        color: 0xffffff,
        transparent: true,
        opacity: 0,
        depthWrite: false,
        blending: THREE.AdditiveBlending
    }));
    hoverGlow.scale.set(14, 14, 1);
    hoverGlow.visible = false;
    wordStarsGroup.add(hoverGlow);

    let introCameraZoom = null;
    let starsRotating = true;

    function onResize() {
        camera.aspect = window.innerWidth / window.innerHeight;
        camera.updateProjectionMatrix();
        renderer.setSize(window.innerWidth, window.innerHeight);
        labelRenderer.setSize(window.innerWidth, window.innerHeight);
    }

    window.addEventListener('resize', onResize);

    function startIntroCameraZoom(durationMs = camCfg.introZoomDurationMs) {
        controls.enabled = false;
        introCameraZoom = {
            startTime: performance.now(),
            duration: durationMs,
            fromPos: new THREE.Vector3(0, 0, camCfg.introDistanceStart),
            toPos: new THREE.Vector3(0, 0, camCfg.introDistanceEnd),
            fromSize: starCfg.introSizeStart,
            toSize: starCfg.introSizeEnd,
            fromOpacity: starCfg.introOpacityStart,
            toOpacity: starCfg.introOpacityEnd
        };
        camera.position.copy(introCameraZoom.fromPos);
        controls.target.set(0, 0, 0);
    }

    function updateIntroCameraZoom(now) {
        if (!introCameraZoom) return;

        const t = Math.min((now - introCameraZoom.startTime) / introCameraZoom.duration, 1);
        const eased = 1 - Math.pow(1 - t, 3);

        camera.position.lerpVectors(introCameraZoom.fromPos, introCameraZoom.toPos, eased);
        material.size = introCameraZoom.fromSize + (introCameraZoom.toSize - introCameraZoom.fromSize) * eased;
        material.opacity = introCameraZoom.fromOpacity + (introCameraZoom.toOpacity - introCameraZoom.fromOpacity) * eased;
        material.needsUpdate = true;

        if (t >= 1) {
            introCameraZoom = null;
            controls.enabled = true;
            controls.update();
        }
    }

    function clearIntroCameraZoom() {
        introCameraZoom = null;
    }

    return {
        THREE,
        scene,
        camera,
        renderer,
        labelRenderer,
        controls,
        stars,
        material,
        position,
        starCount,
        wordStarsGroup,
        linesGroup,
        ghostConstellationsGroup,
        wordGlimmerGeometry,
        wordGlimmerMaterial,
        wordGlimmerPoints,
        hoverGlow,
        starTexture,
        get starsRotating() { return starsRotating; },
        set starsRotating(v) { starsRotating = v; },
        get introCameraZoom() { return introCameraZoom; },
        set introCameraZoom(v) { introCameraZoom = v; },
        startIntroCameraZoom,
        updateIntroCameraZoom,
        clearIntroCameraZoom
    };
}

// --- constellation.js ---
class ConstellationManager {
    constructor(app) {
        this.app = app;
        const sf = app.starfield;
        const cfg = app.config.constellation;

        this.THREE = sf.THREE;
        this.scene = sf.scene;
        this.camera = sf.camera;
        this.controls = sf.controls;
        this.position = sf.position;
        this.starCount = sf.starCount;
        this.stars = sf.stars;
        this.wordStarsGroup = sf.wordStarsGroup;
        this.linesGroup = sf.linesGroup;
        this.ghostConstellationsGroup = sf.ghostConstellationsGroup;
        this.wordGlimmerGeometry = sf.wordGlimmerGeometry;
        this.wordGlimmerMaterial = sf.wordGlimmerMaterial;
        this.hoverGlow = sf.hoverGlow;

        this.GHOST_SPREAD = cfg.ghostSpread;
        this.CONSTELLATION_MIN_DISTANCE = cfg.minDistance;
        this.LAUNCH_ANIMATION_MS = cfg.launchAnimationMs;
        this.DISPERSION_MS = cfg.dispersionMs;

        this.clickableTargets = [];
        this.ghostLines = [];
        this.placedConstellationCenters = [];

        this.totalWords = 0;
        this.constellationComplete = false;
        this.viewOnlyMode = false;
        this.clickedStars = new Set();
        this.wordStars = [];
        this.wordStarByIndex = new Map();
        this.anonymousNodes = new Map();

        this.userConstellationLaunched = false;
        this.launchAnimation = null;
        this.userLaunchCenter = null;
        this.userConstellationName = '';
        this.userNameLabel = null;

        this.constellationMode = false;
        this.selectedStar = null;
        this.dispersingWords = false;
        this.dispersionStart = 0;
        this.constellationCameraFrame = null;

        this.hoveredStar = null;

        this.wordCounter = document.getElementById('word-counter');
        this.constellationHint = document.getElementById('constellation-hint');
        this.downloadButton = document.getElementById('download-constellation');
        this.promptScreen = document.getElementById('prompt-screen');
    }

    pickConstellationCenter() {
        const cfg = this.app.config.constellation;
        const minDist = this.CONSTELLATION_MIN_DISTANCE;

        for (let attempt = 0; attempt < cfg.centerPickAttempts; attempt += 1) {
            const center = new this.THREE.Vector3(
                (Math.random() - 0.5) * cfg.centerSpreadX,
                (Math.random() - 0.5) * cfg.centerSpreadY,
                (Math.random() - 0.5) * cfg.centerSpreadZ
            );

            const tooClose = this.placedConstellationCenters.some((placed) => placed.distanceTo(center) < minDist);
            if (!tooClose) {
                this.placedConstellationCenters.push(center.clone());
                return center;
            }
        }

        const fallback = new this.THREE.Vector3(
            (Math.random() - 0.5) * cfg.centerFallbackSpreadX,
            (Math.random() - 0.5) * cfg.centerFallbackSpreadY,
            (Math.random() - 0.5) * cfg.centerFallbackSpreadZ
        );
        this.placedConstellationCenters.push(fallback.clone());
        return fallback;
    }

    createConstellationNameLabel(name, parent, isMine = false) {
        const labelEl = document.createElement('div');
        labelEl.className = `constellation-name${isMine ? ' mine' : ''}`;
        labelEl.textContent = name;
        const label = new CSS2DObject(labelEl);
        label.position.set(0, 22, 0);
        parent.add(label);

        requestAnimationFrame(() => {
            setTimeout(() => labelEl.classList.add('visible'), 120);
        });

        return label;
    }

    pickStarIndices(count) {
        const cfg = this.app.config.constellation;
        const indices = [];
        const anchor = new this.THREE.Vector3(0, 0, 0);
        const minDist = cfg.pickStarMinDist;
        const maxRadius = cfg.pickStarMaxRadius;
        const candidates = Array.from({ length: this.starCount }, (_, i) => i)
            .filter((i) => {
                const x = this.position[i * 3];
                const y = this.position[i * 3 + 1];
                const z = this.position[i * 3 + 2];
                return anchor.distanceTo(new this.THREE.Vector3(x, y, z)) < maxRadius;
            })
            .sort(() => Math.random() - 0.5);

        for (const idx of candidates) {
            if (indices.length >= count) break;

            const x = this.position[idx * 3];
            const y = this.position[idx * 3 + 1];
            const z = this.position[idx * 3 + 2];

            const tooClose = indices.some((other) => {
                const dx = this.position[other * 3] - x;
                const dy = this.position[other * 3 + 1] - y;
                const dz = this.position[other * 3 + 2] - z;
                return Math.hypot(dx, dy, dz) < minDist;
            });

            if (!tooClose) indices.push(idx);
        }

        while (indices.length < count) {
            const idx = Math.floor(Math.random() * this.starCount);
            if (!indices.includes(idx)) indices.push(idx);
        }

        return indices;
    }

    createWordStar(word, starIndex, wordOrderIndex = 0) {
        const x = this.position[starIndex * 3];
        const y = this.position[starIndex * 3 + 1];
        const z = this.position[starIndex * 3 + 2];
        const target = new this.THREE.Vector3(x, y, z);

        const labelEl = document.createElement('div');
        labelEl.className = 'word-star-label';
        labelEl.textContent = word;
        const label = new CSS2DObject(labelEl);
        label.position.set(0, 0, 0);
        this.wordStarsGroup.add(label);

        const hitArea = new this.THREE.Mesh(
            new this.THREE.SphereGeometry(38, 10, 10),
            new this.THREE.MeshBasicMaterial({ visible: false })
        );
        hitArea.position.copy(target);
        this.wordStarsGroup.add(hitArea);

        const wordStar = {
            word,
            starIndex,
            wordOrderIndex,
            isWord: true,
            label,
            labelEl,
            hitArea,
            target,
            glimmerPhase: Math.random() * Math.PI * 2
        };
        hitArea.userData.starNode = wordStar;
        this.clickableTargets.push(hitArea);
        this.wordStarByIndex.set(starIndex, wordStar);
        this.wordStars.push(wordStar);
    }

    getOrCreateStarNode(starIndex) {
        if (this.wordStarByIndex.has(starIndex)) {
            return this.wordStarByIndex.get(starIndex);
        }

        if (!this.anonymousNodes.has(starIndex)) {
            const target = new this.THREE.Vector3(
                this.position[starIndex * 3],
                this.position[starIndex * 3 + 1],
                this.position[starIndex * 3 + 2]
            );

            const hitArea = new this.THREE.Mesh(
                new this.THREE.SphereGeometry(20, 8, 8),
                new this.THREE.MeshBasicMaterial({ visible: false })
            );
            hitArea.position.copy(target);
            this.wordStarsGroup.add(hitArea);

            const node = {
                starIndex,
                isWord: false,
                target,
                hitArea
            };
            hitArea.userData.starNode = node;
            this.clickableTargets.push(hitArea);
            this.anonymousNodes.set(starIndex, node);
        }

        return this.anonymousNodes.get(starIndex);
    }

    updateWordCounter() {
        const copy = this.app.copy;
        this.wordCounter.textContent = copy.wordCounter
            .replace('{clicked}', this.clickedStars.size)
            .replace('{total}', this.totalWords);
        this.wordCounter.classList.toggle('complete', this.constellationComplete);

        if (this.constellationComplete && !this.userConstellationLaunched) {
            this.constellationHint.textContent = copy.constellationHintComplete;
        }
    }

    finalizeConstellationEditing() {
        this.constellationComplete = true;
        this.clearHoverState();

        if (this.selectedStar) {
            this.highlightStar(this.selectedStar, false);
            this.selectedStar = null;
        }

        this.updateWordCounter();

        setTimeout(() => {
            this.launchConstellation();
        }, this.app.config.constellation.finalizeDelayMs);
    }

    disperseWords(words) {
        const copy = this.app.copy;
        const fadeMs = this.app.config.ui.fadeMs;

        this.app.audio.unlockAudio();
        this.promptScreen.classList.remove('visible');
        this.promptScreen.classList.add('fade-out');

        setTimeout(() => {
            this.promptScreen.style.display = 'none';
        }, fadeMs);

        this.totalWords = words.length;
        this.userConstellationName = deriveEmotionName(words);
        this.clickedStars.clear();
        this.constellationComplete = false;
        this.viewOnlyMode = false;
        this.userConstellationLaunched = false;
        this.selectedStar = null;
        this.userLaunchCenter = null;
        this.userNameLabel = null;
        this.placedConstellationCenters.length = 0;
        resetEmotionNames();
        this.downloadButton.classList.remove('visible');

        const starIndices = this.pickStarIndices(words.length);
        words.forEach((word, i) => {
            this.createWordStar(word, starIndices[i], i);
            this.wordStars[this.wordStars.length - 1].labelEl.classList.add('editing-hint');
        });
        this.updateWordGlimmerGeometry();
        this.frameConstellationForEditing();

        this.constellationMode = true;
        this.dispersingWords = true;
        this.dispersionStart = performance.now();
        this.controls.enableZoom = true;
        this.controls.enablePan = true;
        this.wordGlimmerMaterial.size = 5.8;
        this.wordGlimmerMaterial.opacity = 0.48;
        this.hoverGlow.scale.set(24, 24, 1);

        this.wordCounter.textContent = copy.wordCounter
            .replace('{clicked}', '0')
            .replace('{total}', this.totalWords);
        this.constellationHint.textContent = copy.constellationHintEditing;

        setTimeout(() => {
            this.wordCounter.classList.add('visible');
            this.constellationHint.classList.add('visible');
            this.updateWordCounter();
        }, fadeMs + this.DISPERSION_MS);
    }

    addGhostLine(from, to, parent, targetOpacity) {
        const lineGeo = new this.THREE.BufferGeometry().setFromPoints([from.clone(), to.clone()]);
        const lineMat = new this.THREE.LineBasicMaterial({
            color: 0xffffff,
            transparent: true,
            opacity: 0,
            depthTest: false,
            depthWrite: false
        });
        const line = new this.THREE.Line(lineGeo, lineMat);
        line.renderOrder = 8;
        parent.add(line);
        this.ghostLines.push({ material: lineMat, targetOpacity });
        return line;
    }

    spawnGhostConstellation() {
        const group = new this.THREE.Group();
        const pointCount = 3 + Math.floor(Math.random() * 4);
        const center = this.pickConstellationCenter();
        group.position.copy(center);
        this.createConstellationNameLabel(getNextEmotionName(), group);
        const points = [];

        for (let i = 0; i < pointCount; i++) {
            points.push(new this.THREE.Vector3(
                (Math.random() - 0.5) * 150,
                (Math.random() - 0.5) * 150,
                (Math.random() - 0.5) * 150
            ));

            const dot = new this.THREE.Mesh(
                new this.THREE.SphereGeometry(1.1, 6, 6),
                new this.THREE.MeshBasicMaterial({
                    color: 0xffffff,
                    transparent: true,
                    opacity: 0
                })
            );
            dot.position.copy(points[points.length - 1]);
            dot.userData.targetOpacity = 0.38 + Math.random() * 0.18;
            group.add(dot);
        }

        for (let i = 0; i < pointCount - 1; i++) {
            this.addGhostLine(points[i], points[i + 1], group, 0.42 + Math.random() * 0.16);
        }

        if (pointCount > 3 && Math.random() > 0.4) {
            this.addGhostLine(points[0], points[pointCount - 1], group, 0.36);
        }

        this.ghostConstellationsGroup.add(group);

        group.children.forEach((child) => {
            if (child.isMesh && child.userData.targetOpacity) {
                this.ghostLines.push({ material: child.material, targetOpacity: child.userData.targetOpacity });
            }
        });
    }

    getConstellationCentroid() {
        const centroid = new this.THREE.Vector3();
        this.wordStars.forEach((ws) => centroid.add(ws.target));
        if (this.wordStars.length > 0) {
            centroid.divideScalar(this.wordStars.length);
        }
        return centroid;
    }

    prepareLaunchAnimation() {
        const centroid = this.getConstellationCentroid();
        let maxSpread = 1;

        this.wordStars.forEach((ws) => {
            const distance = ws.target.clone().sub(centroid).length();
            if (distance > maxSpread) maxSpread = distance;
        });

        this.anonymousNodes.forEach((node) => {
            const distance = node.target.clone().sub(centroid).length();
            if (distance > maxSpread) maxSpread = distance;
        });

        const scale = this.GHOST_SPREAD / maxSpread;
        const launchCenter = this.pickConstellationCenter();
        this.userLaunchCenter = launchCenter.clone();

        this.wordStars.forEach((ws) => {
            ws.startPos = ws.target.clone();
            ws.endPos = launchCenter.clone().add(
                ws.target.clone().sub(centroid).multiplyScalar(scale)
            );
        });

        this.anonymousNodes.forEach((node) => {
            node.startPos = node.target.clone();
            node.endPos = launchCenter.clone().add(
                node.target.clone().sub(centroid).multiplyScalar(scale)
            );
        });

        this.linesGroup.children.forEach((line) => {
            const positions = line.geometry.attributes.position.array;
            const startA = new this.THREE.Vector3(positions[0], positions[1], positions[2]);
            const startB = new this.THREE.Vector3(positions[3], positions[4], positions[5]);

            line.userData.startA = startA;
            line.userData.startB = startB;
            line.userData.endA = launchCenter.clone().add(startA.clone().sub(centroid).multiplyScalar(scale));
            line.userData.endB = launchCenter.clone().add(startB.clone().sub(centroid).multiplyScalar(scale));
        });

        const userLabelStart = this.getConstellationCentroid().clone().add(new this.THREE.Vector3(0, 22, 0));
        const userLabelEnd = launchCenter.clone().add(new this.THREE.Vector3(0, 22, 0));

        this.launchAnimation = {
            start: performance.now(),
            duration: this.LAUNCH_ANIMATION_MS,
            cameraStart: this.camera.position.clone(),
            cameraEnd: new this.THREE.Vector3(0, 0, this.app.config.camera.launchEndDistance),
            targetStart: this.controls.target.clone(),
            targetEnd: new this.THREE.Vector3(0, 0, 0),
            userLabelStart,
            userLabelEnd
        };

        const ctrlCfg = this.app.config.controls;
        this.controls.minDistance = ctrlCfg.minDistance;
        this.controls.maxDistance = ctrlCfg.launchMaxDistance;
        this.controls.zoomSpeed = ctrlCfg.zoomSpeed;
        this.controls.enableZoom = true;
        this.controls.enablePan = true;
    }

    addUserConstellationNameLabel() {
        if (this.userNameLabel || !this.userLaunchCenter) return;

        const labelEl = document.createElement('div');
        labelEl.className = 'constellation-name mine';
        labelEl.textContent = this.userConstellationName;
        this.userNameLabel = new CSS2DObject(labelEl);
        this.userNameLabel.position.copy(
            this.launchAnimation?.userLabelStart || this.userLaunchCenter.clone().add(new this.THREE.Vector3(0, 22, 0))
        );
        this.scene.add(this.userNameLabel);
    }

    updateWordGlimmerGeometry() {
        const positions = new Float32Array(this.wordStars.length * 3);
        this.wordStars.forEach((ws, index) => {
            positions[index * 3] = ws.target.x;
            positions[index * 3 + 1] = ws.target.y;
            positions[index * 3 + 2] = ws.target.z;
        });
        this.wordGlimmerGeometry.setAttribute('position', new this.THREE.BufferAttribute(positions, 3));
    }

    applyStarNodePosition(node, pos) {
        node.target.copy(pos);
        if (node.hitArea) node.hitArea.position.copy(pos);
        if (node.label) node.label.position.copy(pos);
        if (node.isWord) this.updateWordGlimmerGeometry();
    }

    updateLaunchAnimation(now) {
        if (!this.launchAnimation) return;

        const progress = Math.min((now - this.launchAnimation.start) / this.launchAnimation.duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        const current = new this.THREE.Vector3();

        this.wordStars.forEach((ws) => {
            current.lerpVectors(ws.startPos, ws.endPos, eased);
            this.applyStarNodePosition(ws, current);
        });

        this.wordGlimmerMaterial.size = this.THREE.MathUtils.lerp(2.2, 1.35, eased);

        this.anonymousNodes.forEach((node) => {
            current.lerpVectors(node.startPos, node.endPos, eased);
            this.applyStarNodePosition(node, current);
        });

        this.linesGroup.children.forEach((line) => {
            if (!line.userData.endA) return;

            const pointA = new this.THREE.Vector3().lerpVectors(line.userData.startA, line.userData.endA, eased);
            const pointB = new this.THREE.Vector3().lerpVectors(line.userData.startB, line.userData.endB, eased);
            line.geometry.setFromPoints([pointA, pointB]);
        });

        this.camera.position.lerpVectors(this.launchAnimation.cameraStart, this.launchAnimation.cameraEnd, eased);
        this.controls.target.lerpVectors(this.launchAnimation.targetStart, this.launchAnimation.targetEnd, eased);

        if (this.userNameLabel && this.launchAnimation.userLabelStart && this.launchAnimation.userLabelEnd) {
            this.userNameLabel.position.lerpVectors(this.launchAnimation.userLabelStart, this.launchAnimation.userLabelEnd, eased);
        }

        if (progress >= 1) {
            this.wordGlimmerMaterial.size = 1.35;
            if (this.userNameLabel) {
                this.userNameLabel.element.classList.add('visible');
            }
            this.launchAnimation = null;
        }
    }

    getWordConstellationBounds() {
        const box = new this.THREE.Box3();
        this.wordStars.forEach((ws) => box.expandByPoint(ws.target));
        if (box.isEmpty()) {
            box.setFromCenterAndSize(new this.THREE.Vector3(0, 0, 0), new this.THREE.Vector3(72, 72, 72));
        }
        return box;
    }

    frameConstellationForEditing(durationMs = this.DISPERSION_MS) {
        const bounds = this.getWordConstellationBounds();
        const center = bounds.getCenter(new this.THREE.Vector3());
        const size = Math.max(bounds.getSize(new this.THREE.Vector3()).length(), 34);
        const viewDistance = size * 0.58 + 14;

        this.constellationCameraFrame = {
            startTime: performance.now(),
            duration: durationMs,
            fromCamera: this.camera.position.clone(),
            toCamera: center.clone().add(new this.THREE.Vector3(0, size * 0.08, viewDistance)),
            fromTarget: this.controls.target.clone(),
            toTarget: center.clone()
        };

        this.controls.minDistance = Math.max(0.006, size * 0.008);
        this.controls.maxDistance = Math.max(viewDistance * 3.4, size * 2.6);
        this.controls.zoomSpeed = 4.5;
    }

    updateConstellationCameraFrame(now) {
        if (!this.constellationCameraFrame) return;

        const t = Math.min((now - this.constellationCameraFrame.startTime) / this.constellationCameraFrame.duration, 1);
        const eased = 1 - Math.pow(1 - t, 3);

        this.camera.position.lerpVectors(
            this.constellationCameraFrame.fromCamera,
            this.constellationCameraFrame.toCamera,
            eased
        );
        this.controls.target.lerpVectors(
            this.constellationCameraFrame.fromTarget,
            this.constellationCameraFrame.toTarget,
            eased
        );

        if (t >= 1) {
            this.constellationCameraFrame = null;
        }
    }

    getUserConstellationBounds() {
        const box = new this.THREE.Box3();

        this.wordStars.forEach((ws) => box.expandByPoint(ws.target));
        this.anonymousNodes.forEach((node) => box.expandByPoint(node.target));

        this.linesGroup.children.forEach((line) => {
            const positions = line.geometry.attributes.position.array;
            box.expandByPoint(new this.THREE.Vector3(positions[0], positions[1], positions[2]));
            box.expandByPoint(new this.THREE.Vector3(positions[3], positions[4], positions[5]));
        });

        if (box.isEmpty() && this.userLaunchCenter) {
            box.setFromCenterAndSize(this.userLaunchCenter, new this.THREE.Vector3(80, 80, 80));
        }

        return box;
    }

    launchConstellation() {
        if (this.userConstellationLaunched || !this.constellationComplete) return;

        const cfg = this.app.config.constellation;
        const copy = this.app.copy;

        this.userConstellationLaunched = true;
        this.viewOnlyMode = true;

        if (this.selectedStar) {
            this.highlightStar(this.selectedStar, false);
            this.selectedStar = null;
        }

        this.prepareLaunchAnimation();
        this.addUserConstellationNameLabel();
        this.constellationHint.textContent = copy.constellationHintLaunched.replace('{name}', this.userConstellationName);

        for (let i = 0; i < cfg.ghostCount; i++) {
            setTimeout(() => this.spawnGhostConstellation(), i * cfg.ghostSpawnIntervalMs);
        }

        setTimeout(() => {
            this.downloadButton.classList.add('visible');
        }, cfg.downloadButtonDelayMs);
    }

    updateGhostConstellations() {
        this.ghostLines.forEach((entry) => {
            entry.material.opacity += (entry.targetOpacity - entry.material.opacity) * 0.05;
        });
    }

    updateDispersion(now) {
        if (!this.dispersingWords) return;

        const t = Math.min((now - this.dispersionStart) / this.DISPERSION_MS, 1);
        const eased = 1 - Math.pow(1 - t, 3);

        this.wordStars.forEach((ws) => {
            ws.label.position.lerpVectors(new this.THREE.Vector3(0, 0, 0), ws.target, eased);
            ws.hitArea.position.copy(ws.label.position);
            this.updateWordGlimmerGeometry();
        });

        this.wordGlimmerMaterial.opacity = 0.3 * eased;

        if (t >= 1) {
            this.dispersingWords = false;
            this.wordStars.forEach((ws) => {
                ws.label.position.copy(ws.target);
                ws.hitArea.position.copy(ws.target);
            });
            this.updateWordGlimmerGeometry();
            this.app.audio.stopIntroSound(this.app.config.audio.stopIntroOnDispersionMs);
        }
    }

    clearHoverState() {
        if (this.hoveredStar?.isWord) {
            this.hoveredStar.labelEl.classList.remove('hover-reveal');
        }
        this.hoveredStar = null;
        this.hoverGlow.visible = false;
        this.hoverGlow.material.opacity = 0;
    }

    setHoveredStar(starNode) {
        if (this.hoveredStar === starNode) return;

        if (this.hoveredStar?.isWord) {
            this.hoveredStar.labelEl.classList.remove('hover-reveal');
        }

        this.hoveredStar = starNode;

        if (!this.hoveredStar?.isWord) {
            this.hoverGlow.visible = false;
            this.hoverGlow.material.opacity = 0;
            return;
        }

        this.hoveredStar.labelEl.classList.add('hover-reveal');
        this.hoverGlow.position.copy(this.hoveredStar.target);
        this.hoverGlow.visible = true;
        this.hoverGlow.material.opacity = 0.42;
    }

    updateWordGlimmer(now) {
        if (this.dispersingWords || this.userConstellationLaunched || this.launchAnimation) return;

        const breathe = Math.sin(now * 0.0009) * 0.03;
        const isHoveringWord = this.hoveredStar?.isWord;
        const isSelectedWord = this.selectedStar?.isWord;

        if (isHoveringWord) {
            this.hoverGlow.material.opacity = 0.48 + Math.sin(now * 0.003) * 0.1;
            this.wordGlimmerMaterial.opacity = 0.62 + breathe;
            this.wordGlimmerMaterial.size = 8.5;
            return;
        }

        this.hoverGlow.visible = false;
        this.wordGlimmerMaterial.opacity = isSelectedWord ? 0.56 + breathe : 0.46 + breathe;
        this.wordGlimmerMaterial.size = isSelectedWord ? 7.2 : 5.8;
    }

    highlightStar(starNode, active) {
        if (!starNode?.isWord) return;

        if (active) {
            starNode.labelEl.classList.add('selected');
        } else {
            starNode.labelEl.classList.remove('selected');
        }
    }

    drawLineBetween(a, b) {
        const points = [a.target.clone(), b.target.clone()];
        const lineGeo = new this.THREE.BufferGeometry().setFromPoints(points);
        const isCertain = a.isWord && b.isWord;
        const lineMat = new this.THREE.LineBasicMaterial({
            color: 0xffffff,
            transparent: true,
            opacity: isCertain ? 0.52 : 0.28,
            depthTest: false,
            depthWrite: false
        });
        const line = new this.THREE.Line(lineGeo, lineMat);
        line.renderOrder = 10;
        this.linesGroup.add(line);
    }

    onStarClick(starNode) {
        if (this.dispersingWords || this.viewOnlyMode || this.userConstellationLaunched) return;

        const previousSelected = this.selectedStar;
        const soundType = this.app.audio.getTouchSoundType(starNode, previousSelected);
        this.app.audio.playStarTouchSound(soundType, starNode);

        const isNewStar = !this.clickedStars.has(starNode.starIndex);
        if (isNewStar) {
            this.clickedStars.add(starNode.starIndex);
            this.updateWordCounter();
        }

        if (!this.constellationComplete) {
            if (this.selectedStar && this.selectedStar !== starNode) {
                this.drawLineBetween(this.selectedStar, starNode);
                this.highlightStar(this.selectedStar, false);
                this.selectedStar = starNode;
                this.highlightStar(this.selectedStar, true);
            } else {
                if (this.selectedStar) {
                    this.highlightStar(this.selectedStar, false);
                }
                this.selectedStar = starNode;
                this.highlightStar(this.selectedStar, true);
            }
        }

        if (isNewStar && this.clickedStars.size >= this.totalWords) {
            this.finalizeConstellationEditing();
        }
    }
}

// --- interaction.js ---
class InteractionManager {
    constructor(app) {
        this.app = app;
        this.sf = app.starfield;
        this.constellation = app.constellation;

        this.raycaster = new this.sf.THREE.Raycaster();
        this.pointer = new this.sf.THREE.Vector2();
        this.pointerDownPos = null;
        this.isOrbiting = false;
    }

    bind() {
        const { renderer } = this.sf;
        const cfg = this.app.config.interaction;

        renderer.domElement.addEventListener('pointerdown', (event) => {
            this.pointerDownPos = { x: event.clientX, y: event.clientY };
        });

        renderer.domElement.addEventListener('mousemove', (event) => {
            const c = this.constellation;
            if (!c.constellationMode || c.dispersingWords || c.viewOnlyMode || c.userConstellationLaunched || this.isOrbiting) {
                c.clearHoverState();
                return;
            }

            const starNode = this.pickStarFromPointer(event);
            if (starNode?.isWord) {
                c.setHoveredStar(starNode);
            } else {
                c.clearHoverState();
            }
        });

        renderer.domElement.addEventListener('mouseleave', () => {
            this.constellation.clearHoverState();
        });

        renderer.domElement.addEventListener('dblclick', (event) => {
            const c = this.constellation;
            if (c.dispersingWords || c.viewOnlyMode) return;
            if (!c.constellationMode && !c.userConstellationLaunched) return;

            const focusPoint = this.pickFocusPoint(event);
            if (focusPoint) {
                this.sf.controls.target.copy(focusPoint);
            }
        });

        renderer.domElement.addEventListener('pointerup', (event) => {
            const c = this.constellation;
            if (!c.constellationMode || c.dispersingWords || c.viewOnlyMode || c.userConstellationLaunched || !this.pointerDownPos) {
                return;
            }

            const dx = event.clientX - this.pointerDownPos.x;
            const dy = event.clientY - this.pointerDownPos.y;
            this.pointerDownPos = null;

            if (Math.hypot(dx, dy) > cfg.clickTolerance) return;

            const starNode = this.pickStarFromPointer(event);
            if (starNode) {
                c.onStarClick(starNode);
            }
        });
    }

    setOrbiting(value) {
        this.isOrbiting = value;
    }

    pickStarFromPointer(event) {
        const c = this.constellation;
        const cfg = this.app.config.interaction;

        this.pointer.x = (event.clientX / window.innerWidth) * 2 - 1;
        this.pointer.y = -(event.clientY / window.innerHeight) * 2 + 1;
        this.raycaster.setFromCamera(this.pointer, this.sf.camera);

        const meshHits = this.raycaster.intersectObjects(c.clickableTargets, false);
        if (meshHits.length > 0 && meshHits[0].object.userData.starNode) {
            return meshHits[0].object.userData.starNode;
        }

        this.raycaster.params.Points.threshold = c.constellationMode && !c.userConstellationLaunched
            ? cfg.pointsThresholdEditing
            : cfg.pointsThresholdDefault;
        const pointHits = this.raycaster.intersectObject(this.sf.stars);
        if (pointHits.length > 0 && pointHits[0].index !== undefined) {
            return c.getOrCreateStarNode(pointHits[0].index);
        }

        return null;
    }

    pickFocusPoint(event) {
        const c = this.constellation;
        const cfg = this.app.config.interaction;
        const { THREE, stars, camera, ghostConstellationsGroup, position } = this.sf;

        this.pointer.x = (event.clientX / window.innerWidth) * 2 - 1;
        this.pointer.y = -(event.clientY / window.innerHeight) * 2 + 1;
        this.raycaster.setFromCamera(this.pointer, camera);

        const ghostMeshes = [];
        ghostConstellationsGroup.traverse((child) => {
            if (child.isMesh) ghostMeshes.push(child);
        });

        const ghostHits = this.raycaster.intersectObjects(ghostMeshes, false);
        if (ghostHits.length > 0) {
            let group = ghostHits[0].object;
            while (group.parent && group.parent !== ghostConstellationsGroup) {
                group = group.parent;
            }
            return group.getWorldPosition(new THREE.Vector3());
        }

        const meshHits = this.raycaster.intersectObjects(c.clickableTargets, false);
        if (meshHits.length > 0 && meshHits[0].object.userData.starNode) {
            return meshHits[0].object.userData.starNode.target.clone();
        }

        this.raycaster.params.Points.threshold = c.constellationMode && !c.userConstellationLaunched
            ? cfg.pointsThresholdEditing
            : cfg.pointsThresholdDefault;
        const pointHits = this.raycaster.intersectObject(stars);
        if (pointHits.length > 0 && pointHits[0].index !== undefined) {
            const index = pointHits[0].index;
            return new THREE.Vector3(
                position[index * 3],
                position[index * 3 + 1],
                position[index * 3 + 2]
            );
        }

        return null;
    }
}

// --- ui.js ---
class UIManager {
    constructor(app) {
        this.app = app;
        this.experienceStarted = false;

        this.introText = document.getElementById('intro-text');
        this.promptScreen = document.getElementById('prompt-screen');
        this.promptInput = document.getElementById('prompt-input');
        this.audioGate = document.getElementById('audio-gate');
        this.downloadButton = document.getElementById('download-constellation');
    }

    bind() {
        const copy = this.app.copy;
        const uiCfg = this.app.config.ui;

        this.introText.textContent = copy.introText;
        document.getElementById('prompt-question').textContent = copy.promptQuestion;
        this.promptInput.placeholder = copy.promptPlaceholder;
        document.getElementById('prompt-hint').textContent = copy.promptHint;
        this.audioGate.querySelector('p').textContent = copy.audioGate;
        this.downloadButton.setAttribute('aria-label', copy.downloadAriaLabel);
        this.downloadButton.setAttribute('title', copy.downloadTitle);
        document.getElementById('constellation-hint').textContent = copy.constellationHintDefault;

        this.promptInput.addEventListener('input', (event) => {
            const limited = this.limitWords(event.target.value);
            if (limited !== event.target.value) {
                event.target.value = limited;
            }
        });

        this.promptInput.addEventListener('keydown', (event) => {
            if (event.key !== 'Enter') return;

            const words = this.promptInput.value.trim().split(/\s+/).filter(Boolean);
            if (words.length === 0) return;

            event.preventDefault();
            this.app.constellation.disperseWords(words);
        });

        this.audioGate.addEventListener('click', () => this.startExperience());
        this.audioGate.addEventListener('keydown', (event) => {
            if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault();
                this.startExperience();
            }
        });
        this.audioGate.setAttribute('tabindex', '0');
    }

    limitWords(value) {
        const maxWords = this.app.config.ui.maxWords;
        const words = value.trim().split(/\s+/).filter(Boolean);
        if (words.length <= maxWords) {
            return value;
        }
        return words.slice(0, maxWords).join(' ');
    }

    showPrompt() {
        this.app.audio.unlockAudio();
        this.app.starfield.clearIntroCameraZoom();
        this.app.starfield.controls.enabled = true;
        this.app.starfield.starsRotating = false;
        this.app.starfield.controls.autoRotate = false;
        this.promptScreen.classList.add('visible');
        this.promptInput.focus();
    }

    startExperience() {
        if (this.experienceStarted) return;
        this.experienceStarted = true;

        const uiCfg = this.app.config.ui;
        const audioCfg = this.app.config.audio;

        this.app.audio.unlockAudio();
        this.app.starfield.startIntroCameraZoom();

        this.audioGate.classList.add('hidden');
        setTimeout(() => this.audioGate.remove(), uiCfg.audioGateRemoveMs);

        setTimeout(() => this.introText.classList.add('visible'), uiCfg.introTextDelayMs);

        setTimeout(() => {
            this.introText.classList.remove('visible');
            this.introText.classList.add('fade-out');
            this.app.audio.fadeIntroToAmbient(audioCfg.introFadeMs);
        }, uiCfg.introTextVisibleUntilMs);

        setTimeout(() => {
            this.introText.remove();
            this.showPrompt();
        }, uiCfg.introTextVisibleUntilMs + uiCfg.fadeMs);
    }
}

// --- export.js ---
function downloadConstellationImage(app) {
    const sf = app.starfield;
    const c = app.constellation;
    const { camera, controls, renderer, labelRenderer, scene, material, ghostConstellationsGroup, wordGlimmerMaterial } = sf;
    const { linesGroup, wordStars, userConstellationName, userNameLabel, getUserConstellationBounds } = c;

    const wordCounter = document.getElementById('word-counter');
    const constellationHint = document.getElementById('constellation-hint');
    const downloadButton = document.getElementById('download-constellation');

    const savedCameraPosition = camera.position.clone();
    const savedControlsTarget = controls.target.clone();
    const savedCameraFov = camera.fov;
    const savedGhostVisible = ghostConstellationsGroup.visible;
    const savedDownloadVisibility = downloadButton.style.visibility;
    const savedHintVisibility = constellationHint.style.visibility;
    const savedCounterVisibility = wordCounter.style.visibility;
    const savedLabelRendererVisibility = labelRenderer.domElement.style.visibility;
    const savedStarOpacity = material.opacity;
    const savedStarSize = material.size;
    const savedWordLabelVisibility = wordStars.map((ws) => {
        const visibility = ws.labelEl.style.visibility;
        ws.labelEl.style.visibility = 'hidden';
        return visibility;
    });
    const savedGlimmerOpacity = wordGlimmerMaterial.opacity;
    const savedGlimmerSize = wordGlimmerMaterial.size;
    const savedLineOpacities = linesGroup.children.map((line) => line.material.opacity);
    const savedUserNameVisibility = userNameLabel
        ? userNameLabel.element.style.visibility
        : '';

    ghostConstellationsGroup.visible = false;
    downloadButton.style.visibility = 'hidden';
    constellationHint.style.visibility = 'hidden';
    wordCounter.style.visibility = 'hidden';
    labelRenderer.domElement.style.visibility = 'hidden';
    if (userNameLabel) userNameLabel.element.style.visibility = 'hidden';

    material.opacity = 0.92;
    material.size = 2.1;
    material.needsUpdate = true;

    wordGlimmerMaterial.opacity = 0.55;
    wordGlimmerMaterial.size = 1.35;

    linesGroup.children.forEach((line) => {
        line.material.opacity = Math.max(line.material.opacity, 0.46);
    });

    const bounds = getUserConstellationBounds();
    const center = bounds.getCenter(new sf.THREE.Vector3());
    const size = Math.max(bounds.getSize(new sf.THREE.Vector3()).length(), 60);

    camera.fov = app.config.export.fov;
    camera.position.copy(center).add(new sf.THREE.Vector3(0, size * 0.18, size * 2.1 + 55));
    camera.lookAt(center);
    controls.target.copy(center);
    camera.updateProjectionMatrix();

    renderer.render(scene, camera);
    renderer.render(scene, camera);

    const width = renderer.domElement.width;
    const height = renderer.domElement.height;
    const composite = document.createElement('canvas');
    composite.width = width;
    composite.height = height;
    const context = composite.getContext('2d');
    context.drawImage(renderer.domElement, 0, 0);

    const labelPosition = center.clone().add(new sf.THREE.Vector3(0, 22, 0)).project(camera);
    if (labelPosition.z < 1) {
        const x = (labelPosition.x * 0.5 + 0.5) * width;
        const y = (-labelPosition.y * 0.5 + 0.5) * height;
        context.font = '12px "Andale Mono", monospace';
        context.fillStyle = 'rgba(255, 255, 255, 0.58)';
        context.textAlign = 'center';
        context.textBaseline = 'bottom';
        context.fillText(userConstellationName, x, y);
    }

    const link = document.createElement('a');
    const safeName = cleanWord(userConstellationName) || 'sestosenso';
    link.download = `costellazione-${safeName}.png`;
    link.href = composite.toDataURL('image/png');
    link.click();

    camera.position.copy(savedCameraPosition);
    controls.target.copy(savedControlsTarget);
    camera.fov = savedCameraFov;
    camera.updateProjectionMatrix();
    material.opacity = savedStarOpacity;
    material.size = savedStarSize;
    material.needsUpdate = true;
    wordGlimmerMaterial.opacity = savedGlimmerOpacity;
    wordGlimmerMaterial.size = savedGlimmerSize;
    linesGroup.children.forEach((line, index) => {
        line.material.opacity = savedLineOpacities[index];
    });
    ghostConstellationsGroup.visible = savedGhostVisible;
    downloadButton.style.visibility = savedDownloadVisibility;
    constellationHint.style.visibility = savedHintVisibility;
    wordCounter.style.visibility = savedCounterVisibility;
    labelRenderer.domElement.style.visibility = savedLabelRendererVisibility;
    wordStars.forEach((ws, index) => {
        ws.labelEl.style.visibility = savedWordLabelVisibility[index];
    });
    if (userNameLabel) {
        userNameLabel.element.style.visibility = savedUserNameVisibility;
    }

    renderer.render(scene, camera);
    labelRenderer.render(scene, camera);
}

// --- app.js ---
class SestoSensoApp {
    constructor() {
        this.ready = false;
        this.interaction = null;
    }

    async init() {
        const config = getConfig();
        const copy = getCopy();

        this.config = config;
        this.copy = copy;
        document.title = copy.pageTitle;

        await loadEmotions();

        this.audio = new AudioManager(config);
        this.starfield = createStarfield(config, (isOrbiting) => {
            this.interaction?.setOrbiting(isOrbiting);
        });
        this.constellation = new ConstellationManager(this);
        this.interaction = new InteractionManager(this);
        this.ui = new UIManager(this);

        this.interaction.bind();
        this.ui.bind();

        document.getElementById('download-constellation').addEventListener('click', () => {
            downloadConstellationImage(this);
        });

        this.ready = true;
    }

    update(now) {
        if (!this.ready) return;

        const sf = this.starfield;
        const c = this.constellation;

        if (sf.starsRotating) {
            sf.stars.rotation.y += this.config.stars.rotationSpeed;
        }

        sf.updateIntroCameraZoom(now);
        c.updateDispersion(now);
        c.updateConstellationCameraFrame(now);
        c.updateLaunchAnimation(now);
        c.updateWordGlimmer(now);
        c.updateGhostConstellations();
        sf.controls.update();
        sf.renderer.render(sf.scene, sf.camera);
        sf.labelRenderer.render(sf.scene, sf.camera);
    }
}

// --- sketch.js ---
let app;

function showBootError(error) {
    const el = document.getElementById('boot-error');
    if (!el) return;

    const message = error?.message || String(error);
    el.hidden = false;
    el.innerHTML = [
        '<strong>Impossibile avviare l\'esperienza.</strong>',
        message,
        '<br><br>Prova a ricaricare la pagina.',
        ' Se il problema persiste, apri <code>apri.bat</code>',
        ' oppure esegui <code>python -m http.server 8765</code>',
        ' e vai su <code>http://localhost:8765</code>.'
    ].join(' ');
    console.error(error);
}

async function bootApp() {
    if (typeof window.p5 !== 'function') {
        throw new Error('p5.js non è stato caricato. Controlla la connessione internet.');
    }

    app = new SestoSensoApp();
    await app.init();
}

const sketch = (p) => {
    p.setup = () => {
        p.noCanvas();
        bootApp().catch(showBootError);
    };

    p.draw = () => {
        if (app?.ready) {
            app.update(performance.now());
        }
    };
};

new p5(sketch);
